using UnityEngine;

public class SpriteExample : MonoBehaviour
{
    // Reference to the SpriteRenderer component
    private SpriteRenderer spriteRenderer;

    // Public variables you can change in the Inspector
    public Color tintColor = Color.white;
    public float alpha = 1f;
    public bool flipX = false;
    public bool flipY = false;

    void Start()
    {
        // Get the SpriteRenderer component
        spriteRenderer = GetComponent<SpriteRenderer>();

        if (spriteRenderer == null)
        {
            Debug.LogError("SpriteRenderer component is missing!");
        }

        // Set initial values
        spriteRenderer.color = tintColor;
        spriteRenderer.flipX = flipX;
        spriteRenderer.flipY = flipY;

        Debug.Log("Sprite: " + spriteRenderer.sprite.name);
    }

    void Update()
    {
        // Example: Change color with keys
        if (Input.GetKeyDown(KeyCode.R))
        {
            spriteRenderer.color = Color.red;
            Debug.Log("Sprite turned red!");
        }
        if (Input.GetKeyDown(KeyCode.G))
        {
            spriteRenderer.color = Color.green;
        }
        if (Input.GetKeyDown(KeyCode.B))
        {
            spriteRenderer.color = Color.blue;
        }
        if (Input.GetKeyDown(KeyCode.W))
        {
            spriteRenderer.color = Color.white;
        }

        // Example: Flip with keys
        if (Input.GetKeyDown(KeyCode.F))
        {
            spriteRenderer.flipX = !spriteRenderer.flipX;
            Debug.Log("Flipped X: " + spriteRenderer.flipX);
        }

        // Example: Fade with alpha
        if (Input.GetKey(KeyCode.UpArrow))
        {
            Color c = spriteRenderer.color;
            c.a += Time.deltaTime;
            if (c.a > 1f) c.a = 1f;
            spriteRenderer.color = c;
        }
        if (Input.GetKey(KeyCode.DownArrow))
        {
            Color c = spriteRenderer.color;
            c.a -= Time.deltaTime;
            if (c.a < 0f) c.a = 0f;
            spriteRenderer.color = c;
        }
    }

    // Public method to change sprite
    public void ChangeSprite(Sprite newSprite)
    {
        if (spriteRenderer != null && newSprite != null)
        {
            spriteRenderer.sprite = newSprite;
            Debug.Log("Sprite changed to: " + newSprite.name);
        }
    }

    // Public method to change color
    public void SetColor(Color newColor)
    {
        if (spriteRenderer != null)
        {
            spriteRenderer.color = newColor;
        }
    }

    // Public method to set alpha
    public void SetAlpha(float newAlpha)
    {
        if (spriteRenderer != null)
        {
            Color c = spriteRenderer.color;
            c.a = Mathf.Clamp01(newAlpha);
            spriteRenderer.color = c;
        }
    }
}

